/**
 * Get the column index in H25_DATA for a given month and day type.
 */
function getColumnIndex(month: number, dayType: DayType): number {
  return (month - 1) * 3 + DAY_TYPE_INDEX[dayType]
}

/**
 * Compute Easter Sunday for a given year (Anonymous Gregorian algorithm).
 */
function easterSunday(year: number): Date {
  const a = year % 19
  const b = Math.floor(year / 100)
  const c = year % 100
  const d = Math.floor(b / 4)
  const e = b % 4
  const f = Math.floor((b + 8) / 25)
  const g = Math.floor((b - f + 1) / 3)
  const h = (19 * a + b - d - g + 15) % 30
  const i = Math.floor(c / 4)
  const k = c % 4
  const l = (32 + 2 * e + 2 * i - h - k) % 7
  const m = Math.floor((a + 11 * h + 22 * l) / 451)
  const month = Math.floor((h + l - 7 * m + 114) / 31)
  const day = ((h + l - 7 * m + 114) % 31) + 1
  return new Date(Date.UTC(year, month - 1, day))
}

/**
 * Get all German nationwide public holidays for a year as YYYY-MM-DD strings.
 */
export function getGermanHolidays(year: number): Set<string> {
  const fmt = (d: Date) => d.toISOString().slice(0, 10)
  const addDays = (d: Date, n: number) => {
    const r = new Date(d)
    r.setUTCDate(r.getUTCDate() + n)
    return r
  }

  const easter = easterSunday(year)
  const holidays = new Set<string>()

  // Fixed holidays
  holidays.add(`${year}-01-01`) // Neujahr
  holidays.add(`${year}-05-01`) // Tag der Arbeit
  holidays.add(`${year}-10-03`) // Tag der Deutschen Einheit
  holidays.add(`${year}-12-25`) // 1. Weihnachtstag
  holidays.add(`${year}-12-26`) // 2. Weihnachtstag

  // Easter-based moveable holidays
  holidays.add(fmt(addDays(easter, -2)))  // Karfreitag
  holidays.add(fmt(addDays(easter, 1)))   // Ostermontag
  holidays.add(fmt(addDays(easter, 39)))  // Christi Himmelfahrt
  holidays.add(fmt(addDays(easter, 50)))  // Pfingstmontag

  return holidays
}

/**
 * Determine the BDEW day type for a given date string (YYYY-MM-DD).
 */
export function getDayType(dateStr: string): DayType {
  const d = new Date(dateStr + 'T12:00:00Z')
  const dow = d.getUTCDay()
  if (dow === 6) return 'SA'

  const year = d.getUTCFullYear()
  const holidays = getGermanHolidays(year)
  if (dow === 0 || holidays.has(dateStr)) return 'FT'

  return 'WT'
}

/**
 * Get hourly SLP weights for a given month and day type.
 * Sums 4 QH slots per hour → returns 24 values.
 * Values are in kWh per 1,000,000 kWh annual consumption.
 */
export function getHourlySlpWeights(month: number, dayType: DayType): number[] {
  const col = getColumnIndex(month, dayType)
  const hourly: number[] = []
  for (let h = 0; h < 24; h++) {
    let sum = 0
    for (let q = 0; q < 4; q++) {
      sum += H25_DATA[h * 4 + q][col]
    }
    hourly.push(sum)
  }
  return hourly
}

/**
 * Get quarter-hourly SLP weights for a given month and day type.
 * Returns 96 values (one per 15-min slot).
 * Values are in kWh per 1,000,000 kWh annual consumption.
 */
export function getQHSlpWeights(month: number, dayType: DayType): number[] {
  const col = getColumnIndex(month, dayType)
  return H25_DATA.map(row => row[col])
}

