const PROFILE_DATA: Record<LoadProfile, number[][]> = {
  H25: H25_DATA,
  P25: P25_DATA,
  S25: S25_DATA,
}

/** Get profile-adjusted QH weights */
export function getProfileQHWeights(month: number, dayType: DayType, profile: LoadProfile = 'H25'): number[] {
  const col = getColumnIndex(month, dayType)
  return PROFILE_DATA[profile].map(row => row[col])
}

/** Get profile-adjusted hourly weights */
export function getProfileHourlyWeights(month: number, dayType: DayType, profile: LoadProfile = 'H25'): number[] {
  if (profile === 'H25') return getHourlySlpWeights(month, dayType)
  const qh = getProfileQHWeights(month, dayType, profile)
  const hourly: number[] = []
  for (let h = 0; h < 24; h++) {
    let sum = 0
    for (let q = 0; q < 4; q++) sum += qh[h * 4 + q]
    hourly.push(sum)
  }
  return hourly
}
